import{c as t,Q as o,j as a,m as r}from"./chunks/framework.BXc4yaFE.js";const c=JSON.parse(`{"title":"Don't Outsource the Learning","description":"","frontmatter":{"title":"Don't Outsource the Learning","date":"2026-05-17T00:00:00.000Z","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-05-17-@addyosmani-228860.md","filePath":"research/tweets/2026-05-17-@addyosmani-228860.md","lastUpdated":1779796674000}`),n={name:"research/tweets/2026-05-17-@addyosmani-228860.md"};function s(i,e,h,d,l,u){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="don-t-outsource-the-learning" tabindex="-1">Don&#39;t Outsource the Learning <a class="header-anchor" href="#don-t-outsource-the-learning" aria-label="Permalink to &quot;Don&#39;t Outsource the Learning&quot;">​</a></h1><p><strong>來源</strong>: <a href="https://x.com/addyosmani" target="_blank" rel="noreferrer">@addyosmani</a> · <a href="https://x.com/addyosmani/status/2056078124346228860" target="_blank" rel="noreferrer">原始推文</a><br><strong>日期</strong>: 2026-05-17<br><strong>統計</strong>: 👍 998 · 🔁 160 · 🔖 1,386 · 👁 76,682<br><strong>評分</strong>: 7.65/10 · <strong>整合決策</strong>: Rule</p><hr><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>AI 工具預設值只優化「關任務」；要在不換工具的情況下改變使用姿態（posture），才能同時保持技術成長，避免累積「認知債」。</p><hr><h2 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h2><ol><li><strong>Cognitive surrender 的獨行版本</strong>：每次讓 AI 解決問題而不理解過程，長期下來無 AI 時的能力悄悄削弱——「每週變弱一點點，但當下感覺不到問題」</li><li><strong>三項研究佐證相同結論</strong>：Anthropic 2026 Python 試驗（AI 組理解 50% vs 手動 67%）、MIT EEG 認知債、CHI 2026 初期錨定效應——工具的姿態（posture），而非工具本身，決定結果</li><li><strong>工具 UX 重力偏向 shipping</strong>：產品團隊以合併 PR 與縮短週期獲得獎勵，不以「讓工程師變強」獲獎；Learning Mode 存在但幾乎沒人用在生產工作</li><li><strong>六種 AI 協助真正失效的情境</strong>：除錯時、模型信心錯誤時、框架遷移時、超出 GitHub 中位數問題時、市場重新定價時</li><li><strong>六個 prompting 姿態調整</strong>：先形成假設、先問解釋後問代碼、開 Learning Mode、PR 審查態度看 AI 輸出、手動重建校準、讓模型事後解釋設計決策</li></ol><hr><h2 id="關鍵數據-工具-引用" tabindex="-1">關鍵數據 / 工具 / 引用 <a class="header-anchor" href="#關鍵數據-工具-引用" aria-label="Permalink to &quot;關鍵數據 / 工具 / 引用&quot;">​</a></h2><ul><li><strong>Anthropic 2026 隨機試驗</strong>：AI 組 50% vs 手動組 67% 理解分數；AI 組內：問概念者 65%+ vs 複製貼上者 40%-</li><li><strong>MIT &quot;Your Brain on ChatGPT&quot;</strong>：EEG 顯示 LLM 組腦部連接最弱；83% LLM 用戶無法引用剛產出的文章任何一行</li><li><strong>CHI 2026</strong>：任務開始時使用 LLM 框定問題 → 後續決策品質可量測地降低（order of operations &gt; total AI usage）</li><li><strong>Anthropic Learning Mode</strong>（Socratic 模式）：概念問答 + 要求先自己寫再繼續；存在但生產中幾乎未使用</li><li>核心公式：<strong>ship 80% + learn 100% &gt; ship 100% + learn 0%</strong>（長期策略）</li></ul><hr><h2 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h2><ol><li><strong>研究引用需確認</strong>：「Anthropic 2026 隨機試驗」與「MIT EEG 研究」均為重要聲明，原始 source 未附連結；自引可信度需獨立驗證</li><li><strong>六種失效情境部分重疊</strong>：「除錯時」與「信心錯誤時」在實務上幾乎同時出現，邊界不清</li><li><strong>&quot;Ship 80% and learn 100%&quot;</strong>：公式優美但在實際衝刺壓力下操作性有限；文章未提出如何在團隊中制度化這個取捨</li></ol><hr><h2 id="_5-維度評分" tabindex="-1">5 維度評分 <a class="header-anchor" href="#_5-維度評分" aria-label="Permalink to &quot;5 維度評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>8</td><td>六個 prompting 姿態直接可整合進 CLAUDE.md 或 coding workflow</td></tr><tr><td>B. 創新性 (20%)</td><td>7</td><td>&quot;posture over tool&quot; 框架新穎；CHI 2026 order-of-operations 發現值得注意</td></tr><tr><td>C. 證據品質 (20%)</td><td>8</td><td>三項研究有具體數字；addyosmani 本人可信度高；研究連結缺失為主要扣分點</td></tr><tr><td>D. 技術深度 (15%)</td><td>6</td><td>偏 career strategy / soft skills；技術細節少</td></tr><tr><td>E. 泛化性 (15%)</td><td>9</td><td>不限語言/框架/工具，適用所有使用 AI coding 的工程師</td></tr></tbody></table><p><strong>加權總分</strong>: 8×0.3 + 7×0.2 + 8×0.2 + 6×0.15 + 9×0.15 = <strong>7.65/10</strong></p><hr><h2 id="整合決策" tabindex="-1">整合決策 <a class="header-anchor" href="#整合決策" aria-label="Permalink to &quot;整合決策&quot;">​</a></h2><p><strong>Rule</strong> — 總分 &gt; 6，核心是通用工作原則（prompting 姿態調整 + ship/learn 雙指標），適合整合進 CLAUDE.md 工作流規範或 coding session 結尾自我評估慣例</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>Right now, it&#39;s too easy to let AI write the code while you skip the learning. The bug gets fixed but your mental model doesn&#39;t move. It might get worse over time. We are silently trading future capability for present-day speed, and the tools won&#39;t force us to do otherwise. That part has to come from you.</p><p>There&#39;s a default loop most of us have settled into. You paste in a spec or error message. The model hands you a fix and the symptom vanishes. You ship. Somewhere in that loop, the messy struggle between problem and solution stops happening at all.</p><p>I&#39;ve written before about cognitive surrender, the moment an AI reviewer&#39;s verdict quietly replaces your own. This is the solo version of that same loop. It&#39;s just you and the model. The model is faster, so you stop trying to compete on comprehension. Across thousands of these small interactions, what you can actually build without an AI looking over your shoulder gets a little weaker every week. None of these moments feel like a problem on the day they happen.</p><p>I&#39;m not anti-AI. I use these tools daily and have shipped more with them in the last year than in the years before it. But the default way we use them is optimized for one thing: closing tasks.</p><p>That is a completely different goal from staying sharp enough to steer them over a career that spans a long time.</p><h2 id="the-studies-are-converging-on-the-same-point" tabindex="-1">The studies are converging on the same point <a class="header-anchor" href="#the-studies-are-converging-on-the-same-point" aria-label="Permalink to &quot;The studies are converging on the same point&quot;">​</a></h2><p>Several pieces of research over the last year have landed in roughly the same place.</p><p>Anthropic ran a randomized trial in early 2026 where engineers learned a new Python library, half with AI assistance and half without. Both groups finished the tasks at the same speed. But the AI group bombed the follow-up comprehension quiz: 50% versus 67% for the manual group, with the gap widening on debugging. The interesting cut was inside the AI group itself. Engineers who used AI to ask conceptual questions scored above 65%. Engineers who copy-pasted the generated code scored under 40%. The tool didn&#39;t determine the outcome. The posture did.</p><p>MIT&#39;s Your Brain on ChatGPT study compared essay writing across LLM, search-engine, and brain-only groups. EEG measurements showed brain connectivity scaling down with every layer of external support. The LLM group showed the weakest coupling. After writing the essay, 83% of LLM users couldn&#39;t quote a single line of what they had just produced. The researchers called this cognitive debt: saving mental effort today, paying for it in critical thinking tomorrow.</p><p>A CHI 2026 study added a related finding. When people had LLM access at the start of a task, the LLM framed the entire problem. Even when the human did the rest of the work themselves, that initial anchoring produced measurably worse decisions. The order of operations mattered more than the total amount of AI used.</p><p>Different methodologies reaching the same conclusion. Using AI without an active intent to learn quietly degrades the skill you&#39;re being paid for.</p><h2 id="the-tools-default-to-shipping-not-teaching" tabindex="-1">The tools default to shipping, not teaching <a class="header-anchor" href="#the-tools-default-to-shipping-not-teaching" aria-label="Permalink to &quot;The tools default to shipping, not teaching&quot;">​</a></h2><p>If you fire up a coding agent and stick to the defaults, everything is tuned for one metric: getting the task done.</p><p>The model writes the code. You accept it. The loop repeats. At no point does the tool pause and ask &quot;what do you think the problem is?&quot; or &quot;try writing the first five lines yourself.&quot;</p><p>That&#39;s where UX gravity is right now. Product teams get rewarded for merged changes and shorter cycle times, not for making you a sharper engineer. We all want fewer keystrokes, so the tools have sanded the friction away. The trouble is that friction was where the learning lived.</p><p>A few companies have tried pushing back on these loops not encouraging us to really learn.</p><p>Anthropic shipped Learning Mode for Claude, which uses Socratic questioning and stops to ask you to write code before continuing. OpenAI and Google have shipped similar features. Almost nobody uses them for real production work though if we&#39;re being real. We&#39;ve quietly filed them under &quot;for students&quot; and that&#39;s a mistake. The same feature that helps a sophomore learn React works for a senior engineer learning Rust. You just have to be willing to feel like a beginner again.</p><h2 id="if-the-ai-can-do-it-why-do-i-need-to-understand-it" tabindex="-1">&quot;If the AI can do it, why do I need to understand it?&quot; <a class="header-anchor" href="#if-the-ai-can-do-it-why-do-i-need-to-understand-it" aria-label="Permalink to &quot;&quot;If the AI can do it, why do I need to understand it?&quot;&quot;">​</a></h2><p>A fair question. For some work, the answer is: maybe...you don&#39;t? If it&#39;s boilerplate, glue code, or a throwaway CI script you&#39;ll never look at again, delegate it. The opportunity cost of memorizing some syntax is too high.</p><p>For real software, pure delegation breaks down in a few specific places.</p><p>When something breaks. AI-generated code crashes the same way human code does. &quot;The agent wrote it&quot; doesn&#39;t help you debug problems. Somebody on the team has to understand the architecture.</p><p>When it&#39;s confidently wrong. LLMs can still hallucinate. The only defense against a plausible-looking incorrect answer is enough expertise to spot it. Bandaids like skills, CLIs etc only get you so far.</p><p>When the foundation changes. Code is temporary; systems are permanent. When frameworks update or a security review flags a structural issue, you can&#39;t re-prompt your way out. You need engineers who understand the system well enough to migrate it.</p><p>When you leave the median. AI is brilliant at problems that have been solved a million times on GitHub. The further you stray from the median, the worse it gets. The hard, undocumented problems, the ones that justify a senior engineer&#39;s salary, still require deep understanding.</p><p>When the market adjusts. Engineers who can only ship with AI, and not without it, are entering a labor pool that is already re-pricing what expertise is worth. If you use AI to skip learning, you&#39;re trading future relevance for a slightly easier Tuesday.</p><h2 id="the-fix-is-in-how-you-prompt" tabindex="-1">The fix is in how you prompt <a class="header-anchor" href="#the-fix-is-in-how-you-prompt" aria-label="Permalink to &quot;The fix is in how you prompt&quot;">​</a></h2><p>The good news is that the same tools that produce cognitive debt can produce sharper engineers. The difference is in what you ask of them.</p><p>Form a hypothesis before you ask. Before requesting a fix, write down two or three sentences on what you think the problem is. Use the model&#39;s answer to test your theory, not to replace it.</p><p>Ask for the explanation before the code. In unfamiliar territory, your first prompt should be something like &quot;explain how this works, what the alternatives are, and what the tradeoffs are.&quot; Ask for the code only after you&#39;ve grasped the concepts.</p><p>Turn on Learning Mode when you&#39;re out of your depth. Yes, it feels slower. That&#39;s the point.</p><p>Treat AI output like a PR from a junior engineer. Read it. Critique it. Push back on it. Would you merge it just because the tests passed? If not, don&#39;t merge it here either.</p><p>Re-derive things by hand once in a while. Take a piece of code the model wrote for you and try to recreate it from scratch. It&#39;s the calibration check that tells you how much you&#39;ve quietly lost.</p><p>Ask the model to teach you what it just did. After it writes a clever function, ask what concepts it used and what you&#39;d need to read to understand the design choice. One extra prompt changes what you take away from the session.</p><p>None of these are dramatic. They&#39;re small posture shifts inside the same tools you&#39;re already using.</p><h2 id="two-metrics-not-one" tabindex="-1">Two metrics, not one <a class="header-anchor" href="#two-metrics-not-one" aria-label="Permalink to &quot;Two metrics, not one&quot;">​</a></h2><p>I&#39;ve started ending coding sessions with a simple question: did I learn anything today, or did I just close issues?</p><p>Sometimes the honest answer is &quot;I just closed issues&quot; and that&#39;s fine. If it becomes the answer for months in a row, cognitive debt is accumulating in the background.</p><p>Ship and learn are two separate metrics. Your manager and your customers will only ever ask about the first one. The second is on you.</p><p>I&#39;d rather ship 80% of what I could have and learn 100% of what I needed to, than the reverse. Over years, those two strategies produce very different engineers.</p><p>You don&#39;t have to choose between using AI and learning. You do have to choose a workflow that does both, because the defaults won&#39;t choose it for you. The tools are ready whenever you are.</p><p>The next boring task you were about to delegate is a good place to start.</p>',64)])])}const g=t(n,[["render",s]]);export{c as __pageData,g as default};
